package com.fmcg.ecommerce.controller.admin; import com.fmcg.ecommerce.common.ApiResponse; import io.swagger.v3.oas.annotations.Operation; import io.swagger.v3.oas.annotations.tags.Tag; import org.springframework.http.ResponseEntity; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*; import java.util.ArrayList; import java.util.HashMap; import java.util.List; import java.util.Map; @RestController @RequestMapping("/api/v1/admin/settlements") @Tag(name = "Admin Settlements", description = "Admin vendor settlements APIs") public class AdminSettlementController { @GetMapping @PreAuthorize("hasRole('ADMIN')") @Operation(summary = "Get all settlements") public ResponseEntity<ApiResponse<List<Map<String, Object>>>> getAllSettlements() { return ResponseEntity.ok(ApiResponse.ok(new ArrayList<>())); } @PostMapping("/{id}/process") @PreAuthorize("hasRole('ADMIN')") @Operation(summary = "Process a settlement") public ResponseEntity<ApiResponse<Map<String, Object>>> processSettlement(@PathVariable Long id) { Map<String, Object> response = new HashMap<>(); response.put("settlementId", id); response.put("status", "PROCESSED"); return ResponseEntity.ok(ApiResponse.ok("Settlement processed", response)); } }
